interface ButtonProps {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'warning';
  shadow?: 'one' | 'two';
  style?: React.CSSProperties;
  children: React.ReactNode;
}
const Button = ({
  variant = 'primary',
  shadow = 'one',
  style,
  children,
}: ButtonProps) => {
  return (
    <button
      style={{
        ...styles.variants[variant],
        ...styles.boxShadow[shadow],
        ...style,
      }}
    >
      {children}
    </button>
  );
};
const styles = {
  variants: {
    primary: { backgroundColor: 'blue', color: 'white' },
    secondary: { backgroundColor: '#fff', color: '#000' },
    danger: { backgroundColor: '#f00', color: '#fff' },
    warning: { backgroundColor: 'yellow', color: '#000' },
    success: { backgroundColor: 'green', color: '#fff' },
  },
  boxShadow: {
    one: { boxShadow: '0 4px 8px rgba(0, 0, 0, 0.3)' },
  },
};
export default Button;

